    private Login login;
    private Registrar registrar;
    
    public void setLogin() { 
        btnEntrar1.setBackground(new Color(31, 58, 95));
        btnRegistrar1.setBackground(new Color(77,120,204));
        
        if (login == null) {
           login = new Login(this); 
        }
        
        painel_geral.removeAll();
        painel_geral.add(login);
        SwingUtilities.updateComponentTreeUI(painel_geral);
    }
    
    public void setRegistrar() {
        btnRegistrar1.setBackground(new Color(31, 58, 95));
        btnEntrar1.setBackground(new Color(77,120,204));
        
        if (registrar == null) {
            registrar = new Registrar(this);
        }
        painel_geral.removeAll();
        painel_geral.add(registrar);
        SwingUtilities.updateComponentTreeUI(painel_geral);
    }
    
    public Main() {
        initComponents();
        setLogin();
    }

